import React, { useState } from "react";
import "./App.css";

const FRACTIONS = [
  { numerator: 1, denominator: 2, color: "#6366F1", label: "1/2" },
  { numerator: 1, denominator: 3, color: "#10B981", label: "1/3" },
  { numerator: 1, denominator: 4, color: "#EF4444", label: "1/4" },
  { numerator: 1, denominator: 6, color: "#F59E0B", label: "1/6" },
  { numerator: 1, denominator: 8, color: "#8B5CF6", label: "1/8" },
];

function FreePlay() {
  const [rows, setRows] = useState([[], [], []]);
  const handleDragStart = (e, fraction) => e.dataTransfer.setData("fraction", JSON.stringify(fraction));
  const handleDragOver = (e) => e.preventDefault();
  const handleDrop = (e, rowIndex) => {
    e.preventDefault();
    const data = e.dataTransfer.getData("fraction");
    if (data) {
      const frac = JSON.parse(data);
      const total = rows[rowIndex].reduce((s, f) => s + f.numerator / f.denominator, 0);
      if (total + (frac.numerator / frac.denominator) <= 1.01) {
        const nr = [...rows];
        nr[rowIndex].push({ ...frac, id: Math.random() });
        setRows(nr);
      }
    }
  };
  return (
    <div className="card">
      <p className="instruction-text">Drag the colorful blocks to build your rows! <br/> Can you make them all the same length? 🎈</p>
      <div className="toolbox">
        {FRACTIONS.map((f, i) => (
          <div key={i} draggable onDragStart={(e) => handleDragStart(e, f)} className="fraction-block" style={{ backgroundColor: f.color }}>
            <span>{f.label}</span>
          </div>
        ))}
      </div>
      {rows.map((row, i) => (
        <div key={i} className="row-container">
          <div onDragOver={handleDragOver} onDrop={(e) => handleDrop(e, i)} className="drop-zone">
            {row.length === 0 && <span className="drop-zone-placeholder">Row {i+1} - Drag blocks here!</span>}
            {row.map((b, bi) => (
              <div key={b.id} onClick={() => { const nr = [...rows]; nr[i].splice(bi,1); setRows(nr); }} className="placed-block" style={{ width: `${(b.numerator/b.denominator)*100}%`, backgroundColor: b.color }}>
                {b.label}
              </div>
            ))}
          </div>
        </div>
      ))}
      <div style={{ textAlign: 'center', marginTop: '2rem' }}>
        <button onClick={() => setRows([[],[],[]])} className="btn-danger">🗑️ Reset Board</button>
      </div>
    </div>
  );
}

function ComparisonGame() {
  const [left, setLeft] = useState(FRACTIONS[0]);
  const [right, setRight] = useState(FRACTIONS[2]);
  const [feedback, setFeedback] = useState("");

  const check = (choice) => {
    const lVal = left.numerator / left.denominator;
    const rVal = right.numerator / right.denominator;
    let correct = false;
    if (choice === ">") correct = lVal > rVal;
    if (choice === "<") correct = lVal < rVal;
    if (choice === "=") correct = Math.abs(lVal - rVal) < 0.001;
    setFeedback(correct ? "🎉 Awesome! You've got a great eye for sizes!" : "🤔 Not quite! Look at which block is longer.");
  };

  const next = () => {
    setLeft(FRACTIONS[Math.floor(Math.random() * FRACTIONS.length)]);
    setRight(FRACTIONS[Math.floor(Math.random() * FRACTIONS.length)]);
    setFeedback("");
  };

  return (
    <div className="card">
      <p className="instruction-text">Fraction Battle! Compare the two blocks below. <br/> Which one is bigger? ⚔️</p>
      <div className="comparison-area">
        <div className="comparison-area" style={{ display: 'flex', justifyContent: 'space-around', alignItems: 'center', background: 'transparent', border: 'none', margin: 0 }}>
          <div className="compare-box">
            <div className="fraction-block" style={{ backgroundColor: left.color, width: '140px', height: '90px', fontSize: '2.5rem' }}>{left.label}</div>
            <div style={{ width: '100%', height: '12px', background: left.color, marginTop: '15px', borderRadius: '10px', opacity: 0.2 }}></div>
          </div>
          <div className="vs-circle">VS</div>
          <div className="compare-box">
            <div className="fraction-block" style={{ backgroundColor: right.color, width: '140px', height: '90px', fontSize: '2.5rem' }}>{right.label}</div>
            <div style={{ width: '100%', height: '12px', background: right.color, marginTop: '15px', borderRadius: '10px', opacity: 0.2 }}></div>
          </div>
        </div>
      </div>
      <div style={{ display: 'flex', justifyContent: 'center', gap: '20px' }}>
        <button onClick={() => check(">")} className="btn-primary" style={{ fontSize: '2.5rem', padding: '0.5rem 2.5rem' }}>{'>'}</button>
        <button onClick={() => check("=")} className="btn-primary" style={{ fontSize: '2.5rem', padding: '0.5rem 2.5rem' }}>{'='}</button>
        <button onClick={() => check("<")} className="btn-primary" style={{ fontSize: '2.5rem', padding: '0.5rem 2.5rem' }}>{'<'}</button>
      </div>
      {feedback && (
        <div style={{ textAlign: 'center', marginTop: '2.5rem', padding: '1.5rem', borderRadius: '1rem', background: feedback.includes("🎉") ? '#ecfdf5' : '#fff1f2' }}>
          <p style={{ fontSize: '1.4rem', fontWeight: '800', margin: 0, color: feedback.includes("🎉") ? '#059669' : '#e11d48' }}>{feedback}</p>
          <button onClick={next} className="btn-primary" style={{ marginTop: '1rem' }}>Next Round ➡️</button>
        </div>
      )}
    </div>
  );
}

function NumberLine() {
  const [target, setTarget] = useState(0.5);
  const [userPos, setUserPos] = useState(0.1);
  const [message, setMessage] = useState("");

  const ticks = [0, 0.25, 0.5, 0.75, 1];
  const labels = ["0", "1/4", "1/2", "3/4", "1"];

  return (
    <div className="card">
      <p className="instruction-text">Find the spot! Drag the pin to <strong>{target === 0.5 ? "1/2" : target === 0.25 ? "1/4" : "3/4"}</strong> on the line. 📍</p>
      <div className="number-line-container">
        <div className="line-axis">
          {ticks.map((t, i) => (
            <div key={i} className="tick" style={{ left: `${t * 100}%` }}>
              <span className="tick-label">{labels[i]}</span>
            </div>
          ))}
          <div className="pin" style={{ left: `${userPos * 100}%` }}
            onMouseDown={(e) => {
              const move = (me) => {
                const rect = e.currentTarget.parentElement.getBoundingClientRect();
                setUserPos(Math.max(0, Math.min(1, (me.clientX - rect.left) / rect.width)));
              };
              const up = () => { window.removeEventListener('mousemove', move); window.removeEventListener('mouseup', up); };
              window.addEventListener('mousemove', move); window.addEventListener('mouseup', up);
            }}
          >📍</div>
        </div>
      </div>
      <div style={{ textAlign: 'center', marginTop: '5rem' }}>
        <button onClick={() => setMessage(Math.abs(userPos - target) < 0.05 ? "🎯 Perfect! You're a pro!" : "🤏 So close! Try moving it a tiny bit.")} className="btn-primary">Check My Answer</button>
        {message && <p style={{ fontSize: '1.3rem', fontWeight: '800', marginTop: '1.5rem', color: message.includes("🎯") ? 'var(--success)' : 'var(--text-main)' }}>{message}</p>}
        <button onClick={() => { setTarget([0.25, 0.5, 0.75][Math.floor(Math.random()*3)]); setMessage(""); }} className="btn-primary" style={{ marginLeft: '1rem', background: 'var(--accent)' }}>New Challenge</button>
      </div>
    </div>
  );
}

function EquivalentsFinder() {
  const [blocks, setBlocks] = useState([]);
  const currentTotal = blocks.reduce((s, f) => s + f.numerator/f.denominator, 0);

  const handleDrop = (e) => {
    e.preventDefault();
    const data = JSON.parse(e.dataTransfer.getData("fraction"));
    if (currentTotal + (data.numerator/data.denominator) <= 0.501) {
      setBlocks([...blocks, { ...data, id: Math.random() }]);
    }
  };

  return (
    <div className="card">
      <p className="instruction-text">Matching Challenge! 🧩 <br/> Can you make exactly <strong>1/2</strong> using other blocks?</p>
      <div className="match-target" style={{ height: '80px', fontSize: '2rem', background: '#eff6ff' }}>Goal: 1/2</div>
      <div className="toolbox">
        {FRACTIONS.filter(f => f.denominator > 2).map((f, i) => (
          <div key={i} draggable onDragStart={(e) => e.dataTransfer.setData("fraction", JSON.stringify(f))} className="fraction-block" style={{ backgroundColor: f.color }}>{f.label}</div>
        ))}
      </div>
      <div onDragOver={(e) => e.preventDefault()} onDrop={handleDrop} className="drop-zone" style={{ height: '100px', maxWidth: '400px', margin: '0 auto' }}>
        {blocks.length === 0 && <span className="drop-zone-placeholder">Drop blocks here to match 1/2</span>}
        {blocks.map(b => (
          <div key={b.id} className="placed-block" style={{ width: `${(b.numerator/b.denominator)*200}%`, backgroundColor: b.color }}>{b.label}</div>
        ))}
      </div>
      {Math.abs(currentTotal - 0.5) < 0.01 && (
        <div style={{ textAlign: 'center', marginTop: '2rem', animation: 'popIn 0.5s ease' }}>
          <h2 style={{ color: 'var(--success)' }}>✨ You Found a Match! ✨</h2>
          <p style={{ fontSize: '1.1rem', fontWeight: '700' }}>{blocks.length} blocks of {blocks[0].label} is the same as 1/2!</p>
        </div>
      )}
      <button onClick={() => setBlocks([])} className="btn-danger" style={{ display: 'block', margin: '2rem auto' }}>Reset Puzzle</button>
    </div>
  );
}

function FractionKitchen() {
  const [bowlAmount, setBowlAmount] = useState(0);
  const target = 0.75;

  return (
    <div className="card">
      <p className="instruction-text">Chef's Helper! 🥣 <br/> The recipe needs exactly <strong>3/4</strong> cup of sugar.</p>
      <div className="kitchen-container" style={{ justifyContent: 'center' }}>
        <div className="bowl-area">
          <div className="mixing-bowl">
            <div className="bowl-fill" style={{ height: `${bowlAmount * 100}%` }}></div>
          </div>
          <div style={{ marginTop: '2.5rem', display: 'flex', gap: '1.5rem' }}>
            <button onClick={() => bowlAmount + 0.25 <= 1.01 ? setBowlAmount(bowlAmount + 0.25) : null} className="btn-primary" style={{ background: '#f59e0b' }}>➕ Add 1/4 Cup</button>
            <button onClick={() => bowlAmount + 0.5 <= 1.01 ? setBowlAmount(bowlAmount + 0.5) : null} className="btn-primary" style={{ background: '#d97706' }}>➕ Add 1/2 Cup</button>
          </div>
          <p style={{ fontWeight: '800', fontSize: '1.2rem', marginTop: '1.5rem' }}>Bowl Status: {Math.round(bowlAmount * 100)}% Full</p>
          {Math.abs(bowlAmount - target) < 0.01 && <h2 style={{ color: 'var(--success)', animation: 'popIn 0.5s' }}>🧁 Perfect! Time to bake! 🧁</h2>}
          <button onClick={() => setBowlAmount(0)} className="btn-danger" style={{ marginTop: '1.5rem' }}>Empty Bowl</button>
        </div>
      </div>
    </div>
  );
}

export default function App() {
  const [activeTab, setActiveTab] = useState("free");
  const tabs = [
    { id: "free", label: "Play", icon: "🎈", color: "var(--primary)" },
    { id: "compare", label: "Battle", icon: "⚔️", color: "var(--secondary)" },
    { id: "line", label: "Line", icon: "📍", color: "var(--accent)" },
    { id: "match", label: "Match", icon: "🧩", color: "var(--success)" },
    { id: "kitchen", label: "Bake", icon: "🥣", color: "var(--warning)" }
  ];

  return (
    <div className="app-container">
      <header className="app-header">
        <h1 className="app-title">Fraction Fun!</h1>
        <p className="app-subtitle">The most colorful way to learn math!</p>
      </header>

      <nav className="nav-menu">
        {tabs.map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id)} className={`nav-button ${activeTab === t.id ? "active" : ""}`} style={{ backgroundColor: activeTab === t.id ? t.color : '' }}>
            <span>{t.icon}</span> {t.label}
          </button>
        ))}
      </nav>

      <main>
        {activeTab === "free" && <FreePlay />}
        {activeTab === "compare" && <ComparisonGame />}
        {activeTab === "line" && <NumberLine />}
        {activeTab === "match" && <EquivalentsFinder />}
        {activeTab === "kitchen" && <FractionKitchen />}
      </main>
    </div>
  );
}
